class Solution:
    def minCost(self, nums, cost):
        pairs = sorted(zip(nums, cost))
        total = sum(cost)
        half = total / 2
        acc = 0
        target = pairs[0][0]
        for v, c in pairs:
            acc += c
            if acc >= half:
                target = v
                break
        return sum(abs(v - target) * c for v, c in zip(nums, cost))

