var minCost = function(nums, cost) {
    const pairs = nums.map((v, i) => [v, cost[i]]);
    pairs.sort((a, b) => a[0] - b[0]);
    let total = 0;
    for (const c of cost) total += c;
    const half = total / 2;
    let acc = 0;
    let target = pairs[0][0];
    for (const [v, c] of pairs) {
        acc += c;
        if (acc >= half) { target = v; break; }
    }
    let ans = 0;
    for (let i = 0; i < nums.length; i++) ans += Math.abs(nums[i] - target) * cost[i];
    return ans;
};
